// Render een eenvoudige A4 HTML-cheatsheet met ruime aantekenvlakken die
// 1-op-1 mappen op Mautic-velden. Een volgende node (bijv. Gotenberg/HTML-to-PDF)
// zet dit om naar PDF. Hier houden we het HTML zodat het zonder extra binaries werkt.
const ctx = $input.first().json;
const k = ctx.kijker || {};
const w = ctx.woning || {};
const a = ctx.afspraak || {};

const html = `<!DOCTYPE html><html lang="nl"><head><meta charset="utf-8"><style>
  body{font-family:system-ui,sans-serif;color:#1f2937;margin:24px;font-size:13px}
  h1{font-size:18px;margin:0 0 4px} h2{font-size:14px;border-bottom:1px solid #e5e7eb;padding-bottom:2px;margin-top:18px}
  .vak{border:1px solid #cbd5e1;border-radius:6px;min-height:60px;margin-top:6px;padding:6px}
  .label{font-weight:600;font-size:12px;color:#475569}
</style></head><body>
  <h1>Bezichtiging — ${a.contactNaam || ''}</h1>
  <div>${w.titel || ''} · ${a.begin || ''}</div>
  <h2>Kijker</h2>
  <div>${(k.aiAnalyse && k.aiAnalyse.huidigeSituatie) || ''}</div>
  <h2>Kwalificatie</h2>
  <div>Eigen woning: ${k.kwalificatie?.heeftEigenWoning ?? '-'} · Overweegt verkoop: ${k.kwalificatie?.overwegtVerkoop ?? '-'}</div>
  <h2>Aantekeningen (worden teruggelezen)</h2>
  <div class="label">Notities bezichtiging</div><div class="vak"></div>
  <div class="label">Interesse 0–100</div><div class="vak"></div>
  <div class="label">Vervolgactie</div><div class="vak"></div>
</body></html>`;

return [{ json: { afspraakId: ctx.afspraak?.id, html, bestandsnaam: `bezichtiging-${ctx.afspraak?.id || 'onbekend'}.html` } }];
